arguments.argument:
if global.gamePaused=false
{
  if init=0
    init=1
  if decayTime!=-100
  {
    decayTime-=1
    if decayTime<=0 {instance_destroy()}
  }
  
  speed=bulletSpeed
  if sprite_index=sRidleyFireball
  {
    image_xscale+=0.01; image_yscale+=0.01
    image_angle-=15
  }
}
else {speed=0}
